#include<bits/stdc++.h>
#define ll long long
using namespace std;
ll n, k, cnt;
void dfs(ll x, ll y, ll z) {
	if (y == k + 1) {
		if (z == n) {
			cnt++;
		}
		return;
	}
	for (int i = x; i + z <= n; i++) {
		dfs(i, y + 1, i + z);
	}

}
int main() {
	cin >> n >> k;
	dfs(1, 1, 0);
	cout << cnt;
}
